  ('social-worker-moex-02105', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '試問處遇性團體與任務性團體有何不同？', '["處遇性團體以達到團體目標為主；任務性團體具有教育功能", "處遇性團體具有治療功能；任務性團體以成員的情緒支持為主", "處遇性團體以滿足成員的成長性需求為主；任務性團體以完成任務為主要目標", "兩者沒有不同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02106', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「轉介」是服務案主過程中常用到的技巧，請問社會工作者在轉介時，最需要遵循那一個原則以避免案 主拒絕？', '["讓案主表達感受、了解其所需", "承諾案主會提供最適當的資源", "對於轉介後服務提供者的內容與品質進行保證", "說明轉介服務的好處，並鼓勵案主接受轉介"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02107', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一位逃家少女跟社工說：「我對於爸爸管教的方法實在無法接受，爸爸很明顯的偏愛哥哥，家裡有好吃的 都先給哥哥吃，我什麼都沒有，還得幫忙照顧妹妹，妹妹也只會撒嬌，我變成了家人的眼中釘，既然 如此，那乾脆離開這個家，省得家人看到我就覺得礙眼…..」聽完這個少女對家人的描述後，社工回答： 「雖然我不是你，但是聽起來，你覺得難受，也很受傷，因為妳覺得爸爸偏心。」請問這位社工所用的 是那一種技巧？', '["再框架（reframing）", "同理（empathy）", "充權（empowerment）", "真誠（authenticity）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02108', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作發展中十分具有影響力的慈善組織會社（Charity Organization Society, COS），下列敘述何者正 確？', '["於1887年在英國倫敦開始建立了第一個組織", "從事濟貧的工作", "由公部門主導的社會工作模式", "運用大學生進入社區提供服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02109', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '試問綜融社會工作實務的內涵是？', '["了解體系內、體系間和環境體系等多元體系的改變潛力", "用標準化作業流程將社會工作服務分為案主及社會環境，分別處理個別的議題", "綜融社會工作者不需要了解社會政策", "社會工作者的權益保障高於案主的權益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
